solution: ```class Solution {
public:
    int magicalString(int n) {
        if (n == 0) return 0;
        if (n <= 3) return 1;
        string s(n, '0');
        s[0] = '1';
        s[1] = '2';
        s[2] = '2';
        int idx = 2;
        int pos = 3;
        int count = 1;
        while (pos < n) {
            int len = s[idx] - '0';
            char c = (s[pos - 1] == '1') ? '2' : '1';
            for (int i = 0; i < len && pos < n; ++i) {
                s[pos] = c;
                if (c == '1') ++count;
                ++pos;
            }
            ++idx;
        }
        return count;
    }
};
